INSERT INTO `category` (`id`, `name`, `tag`, `slug`, `image`, `createdAt`, `updatedAt`, `description`, `active_filters`, `display_order`, `metaTitle`, `metaDescription`, `metaKeywords`) VALUES
('a80xzss20', 'Rubber Seals', NULL, 'rubber-seals', 'https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Rubber-seal.png', '2026-03-13 18:30:03.241', '2026-03-19 11:46:01.114', '   Rubber seals are designed to provide effective sealing and protection for connector systems, preventing the entry of moisture, dust and contaminants. Made from high-quality materials such as silicone, they ensure reliable insulation and long-lasting performance in automotive and industrial environments. ', '[\"categoryNumber\", \"series\", \"way\", \"mf\"]', 3, NULL, NULL, NULL),
('ja4jo8lkz', 'Terminals', NULL, 'terminals', 'https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Terminals%20-Products.png', '2026-03-13 12:04:33.631', '2026-03-19 11:45:40.042', 'Terminals are precision-engineered electrical connectors designed to ensure secure and reliable connections in automotive wiring harness systems. Manufactured with high-quality materials and advanced stamping processes, they provide excellent conductivity, durability and consistent performance across demanding automotive applications.', '[\"categoryNumber\", \"series\", \"way\", \"material\", \"colour\", \"mf\", \"sealed\"]', 2, NULL, NULL, NULL),
('jbyqp6s65', 'Connection Systems', 'Integrated', 'connectors', 'https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Connectors.png', '2026-02-26 13:09:00.270', '2026-03-16 15:12:15.792', 'Connection Systems specializes in manufacturing precision connectors and engineering components for the automotive and industrial sectors. It delivers high-quality, reliable connection systems that meet global standards and support leading OEMs with innovative and scalable manufacturing solutions.', '[\"series\", \"way\", \"material\", \"sealed\", \"categoryNumber\"]', 1, NULL, NULL, NULL),
('ymetp4rk7', 'Cases & Cable Tie', NULL, 'cases-cable-tie', 'https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Cabletie-cases.png', '2026-03-13 18:30:33.716', '2026-03-19 11:46:52.142', ' Essential components used for organizing, protecting, and securing electrical wiring and connectors in automotive systems. Manufactured using durable materials and strict quality standards, they provide reliable protection and efficient cable management for various ', '[\"categoryNumber\", \"series\", \"way\", \"material\"]', 4, NULL, NULL, NULL);
