INSERT INTO `page_sections` (`id`, `pageId`, `type`, `content`, `sortOrder`, `isActive`, `createdAt`, `updatedAt`) VALUES
('8ca6f812-22b1-11f1-bbf5-0ef06123998a', 'cfea0507-22b0-11f1-bbf5-0ef06123998a', 'about-hero', '{\"title\": \"About Besmak \", \"description\": \"Delivering precision and quality in industrial manufacturing for over two decades.\"}', 10, 1, '2026-03-18 10:02:18', '2026-03-18 10:17:33'),
('8ca705b3-22b1-11f1-bbf5-0ef06123998a', 'cfea0507-22b0-11f1-bbf5-0ef06123998a', 'about-content', '{\"title\": \"Our Story\", \"description1\": \"Founded in 2004, Besmak India has grown from a small workshop to a leading name in precision manufacturing. We specialize in high-quality industrial components that meet the rigorous standards of B2B clients worldwide.\", \"description2\": \"Our state-of-the-art facility and experienced team ensure that every part we produce is a testament to our commitment to excellence.\"}', 20, 1, '2026-03-18 10:02:18', '2026-03-18 10:02:18'),
('8ca84a64-22b1-11f1-bbf5-0ef06123998a', 'contact-page', 'contact-hero', '{\"bgImage\": \"/images/contact-hero.png\", \"btn1Url\": \"tel:+914467123333\", \"btn2Url\": \"#\", \"btn1Text\": \"Call Now\", \"btn2Text\": \"Live Chat\", \"topTitle\": \"Let\'s Build the Future, Together\", \"mainTitle\": \"Let\'s Build Something Amazing Together\", \"emailLabel\": \"Email\", \"emailValue\": \"sales@besmakindia.com\", \"phoneLabel\": \"Phone\", \"phoneValue\": \"+91 44 6712 3333\", \"description\": \"At Besmak Components Pvt Ltd, we believe every project begins with a conversation. Whether you’re exploring new components, seeking technical support, or looking for a long-term strategic partner, our team is ready to assist you.\", \"addressLabel\": \"Address\", \"addressValue\": \"Plot No. A-45, SIPCOT Industrial Growth Center, Oragadam, Kanchipuram - 602118\", \"contactTitle\": \"Contact Information\"}', 10, 1, '2026-03-18 10:02:18', '2026-03-18 10:14:33'),
('8ca855ef-22b1-11f1-bbf5-0ef06123998a', 'contact-page', 'contact-address', '{\"heading\": \"Manufacturing Locations\", \"bgHeading\": \"WORKS\", \"card1_city\": \"Kanchipuram, Tamil Nadu\", \"card2_city\": \"Chennai, Tamil Nadu\", \"card3_city\": \"Ahmedabad, Gujarat\", \"card1_email\": \"sales@besmakindia.com\", \"card1_phone\": \"+91 44 6712 3333\", \"card1_title\": \"Oragadam Plant\", \"card2_title\": \"Athipet Plant\", \"card3_title\": \"Sanand Plant\", \"card1_header\": \"REGD. OFFICE & WORKS I\", \"card2_footer\": \"Chennai Manufacturing Unit\", \"card2_header\": \"WORKS II\", \"card3_footer\": \"West India Manufacturing Unit\", \"card3_header\": \"WORKS III\", \"bottom_header\": \"DESIGN OFFICE - CHENNAI\", \"card1_address\": \"Plot No. A-45, SIPCOT Industrial Growth Center,\\nOragadam Industrial Corridor,\\nOragadam, Sriperumbudur Taluka,\\nKanchipuram – 602118\\nTamil Nadu, India\", \"card2_address\": \"No.1, Ganesh Road,\\nNageswara Rao Road Extn,\\nAthipet,\\nChennai - 600058\\nTamil Nadu, India\", \"card3_address\": \"Survey No. 627/B,\\nOpp. Virochannagar Railway Station,\\nNear Khoraj Village,\\nSanand Taluka,\\nAhmedabad – 382170\\nGujarat, India\", \"bottom_address\": \"The Executive Zone Pvt. Ltd., Shakthi Towers, Ground Floor, Tower 1, No. 766, Anna Salai, Chennai - 600002, Tamil Nadu\"}', 20, 1, '2026-03-18 10:02:18', '2026-03-18 10:02:18'),
('8ca85870-22b1-11f1-bbf5-0ef06123998a', 'contact-page', 'contact-form', '{\"heading\": \"Tell us about your requirements.\", \"topText\": \"PRODUCT ENQUIRY\", \"div1_name\": \"Connection Systems\", \"div2_name\": \"Engineering Products Division\", \"div3_name\": \"Precision Stamping Division\", \"div4_name\": \"CNH Moulds\", \"nameLabel\": \"YOUR NAME\", \"buttonText\": \"SEND ENQUIRY\", \"emailLabel\": \"EMAIL ADDRESS\", \"description\": \"Whether you need automotive connectors, terminals or complete wiring harness solutions — our team responds promptly.\", \"mobileLabel\": \"MOBILE NUMBER\", \"addressLabel\": \"YOUR ADDRESS\", \"messageLabel\": \"MESSAGE\", \"subjectLabel\": \"SUBJECT\"}', 30, 1, '2026-03-18 10:02:18', '2026-03-18 10:02:18'),
('8ca85a15-22b1-11f1-bbf5-0ef06123998a', 'contact-page', 'contact-info', '{\"heading\": \"3 Warehouses\", \"wh1_city\": \"Kanchipuram, Tamil Nadu\", \"wh2_city\": \"Pune, Maharashtra\", \"wh3_city\": \"Gurgaon, Haryana\", \"wh1_badge\": \"ORAGADAM\", \"wh1_email\": \"\", \"wh1_phone\": \"\", \"wh1_title\": \"WH — 01\", \"wh2_badge\": \"PUNE\", \"wh2_email\": \"besmakpune@besmakindia.com\", \"wh2_phone\": \"+91 89255 19917\", \"wh2_title\": \"WH — 02\", \"wh3_badge\": \"GURGAON\", \"wh3_email\": \"besmakgurgaon@besmakindia.com\", \"wh3_phone\": \"+91 93404 74340 / 90752 84396\", \"wh3_title\": \"WH — 03\", \"wh1_address\": \"Plot No:16, Venkateswara Nagar, Stage-III,\\nMettupalayam Village, Oragadam\\nIndustrial Area,\\nSriperumbudur Taluk, Kanchipuram –\\n602118\", \"wh2_address\": \"Door No.1, Gate No.201,\\nVillage Chimball, Khed,\\nPune – 410 501\", \"wh3_address\": \"Village Kheri Dhoula, NH-48,\\nOpp. Grozz Toll, Killa No.15,\\nKharsra No. 1531, Gurgaon – 122004\"}', 40, 1, '2026-03-18 10:02:18', '2026-03-18 10:02:18'),
