('about-capabilities', 'about-page', 'about-capabilities', '{\"leftColumn\": {\"rows\": [{\"label\": \"Machine Capacity\", \"value\": \"Up to 500 Tons\"}, {\"label\": \"Mould Weight\", \"value\": \"Up to 5 Tons\"}, {\"label\": \"Annual Capacity\", \"value\": \"100 Moulds / Year\"}], \"title\": \"MOULD MAKING\", \"description\": \"We have the capability to design and build complex moulds for machines up to 500 Tons. Our in-house mould-making facility ensures reduced lead times, tighter tolerances, and full control over quality.\"}, \"rightColumn\": {\"rows\": [{\"label\": \"Approach\", \"value\": \"Design to Delivery\"}, {\"label\": \"Team\", \"value\": \"Qualified Engineers\"}, {\"label\": \"Commitment\", \"value\": \"On-Time Every Time\"}], \"title\": \"PROJECT MANAGEMENT\", \"description\": \"A dedicated team of qualified and experienced engineers handle every project awarded to us by our customers. Right from the start, this team works closely with customers till the part is proven to their satisfaction.\"}}', 4, 0, '2026-03-10 10:06:45', '2026-03-10 10:06:45'),
