('about-content-1', 'about-page', 'about-content', '{\"title\": \"Our Story\", \"description1\": \"Founded in 2004, Besmak India has grown from a small workshop to a leading name in precision manufacturing. We specialize in high-quality industrial components that meet the rigorous standards of B2B clients worldwide.\", \"description2\": \"Our state-of-the-art facility and experienced team ensure that every part we produce is a testament to our commitment to excellence.\"}', 0, 0, '2026-03-02 12:35:01', '2026-03-02 12:35:01'),
('about-feature-cards', 'about-page', 'about-feature-cards', '{\"cards\": [{\"icon\": \"Briefcase\", \"tags\": [\"60M / month\", \"1-20 pole\"], \"theme\": \"blue\", \"title\": \"CONNECTORS\", \"description\": \"Equipped with Tool Design, Validation and Manufacturing – high end connectors from 1-pole to 20-pole, PCB mounting and wire-to-wire assemblies meeting industry-specified quality expectations.\"}, {\"icon\": \"Wrench\", \"tags\": [\"EV Ready\", \"Insert Moulded\"], \"theme\": \"green\", \"title\": \"SPECIAL CUSTOMISED PARTS\", \"description\": \"Leveraging stamping and moulding capabilities, we develop precision insert moulded parts for Sensors, Actuators, Turbo Chargers, Body Control Modules, and Socket Chargers for EVs.\"}, {\"icon\": \"Zap\", \"tags\": [\"60M / month\", \"Gold / Silver coat\"], \"theme\": \"red\", \"title\": \"TERMINALS\", \"description\": \"High Speed Stamping Line for manufacture of Terminals and Stamped parts. Tooling to Production capability with dedicated vendor base supporting special coatings like gold and silver.\"}]}', 5, 0, '2026-03-10 11:24:20', '2026-03-10 11:24:20'),
('about-hero-1', 'about-page', 'about-hero', '{\"title\": \"About Besmak India\", \"description\": \"Delivering precision and quality in industrial manufacturing for over two decades.\"}', 0, 0, '2026-03-02 12:35:01', '2026-03-02 12:35:01'),
('about-icon-boxes-1', 'about-page', 'about-icon-boxes', '{\"boxes\": [{\"icon\": \"Gauge\", \"description\": \"Started in 1987 with toolroom, Besmak components incorporated on 1994. Besmak Components has provided high quality auto parts for over 25 years supporting the Automotive Wiring Harness in two wheeler and four wheeler segments.\"}, {\"icon\": \"Trophy\", \"description\": \"25 years of expertise in manufacturing connectors and solutioned auto components for the Wiring Harness Industry.\"}, {\"icon\": \"Check\", \"description\": \"Founded and promoted by Mr. C.N. HARI, the Company has developed a wide range of connectors and auto parts.\"}]}', 4, 0, '2026-03-10 06:18:31', '2026-03-10 06:18:31'),
('about-milestones-1', 'about-page', 'about-milestones', '{\"imageUrl\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak%20Milestone%20edited%20%281%29.png\", \"topTitle\": \"OUR JOURNEY\", \"mainTitle\": \"Milestones\", \"description\": \"From a humble beginning in 1987 to becoming a globally-aspiring automotive components manufacturer — every year has been a step forward in precision and purpose.\"}', 8, 1, '2026-03-13 09:33:33', '2026-03-13 09:33:33'),
('card-grid-section', 'home-page-id', 'card-grid', '{\"title\": \"Our Strategic Verticals\", \"subtitle\": \"At Besmak, we are not just building products. We are shaping the future of manufacturing — with purpose, passion and progress. Across every vertical, our focus remains on innovation, operational excellence and long term value for our customers, employees and stakeholders.\", \"card1Title\": \"Connectors\", \"card2Title\": \"Fuse Box\", \"card3Title\": \"Dummy Plugs\"}', 4, 1, '2026-03-05 08:36:15', '2026-03-05 15:03:39'),
('career-form-section-1', 'career-page', 'career-form', '{\"title\": \"Apply Now\"}', 3, 1, '2026-03-12 07:05:53', '2026-03-13 06:42:12'),
('career-intro-1', 'career-page', 'career-intro', '{\"line1\": \"We offer an opportunity for continuous learning and growth. Our success lies in total employee involvement.\", \"line2\": \"We are in the path of building a strong TQM / TPM culture.\", \"line3\": \"Our diverse manufacturing operations from Tooling, Moulding, Assembly to final product build offers an exciting opportunity for learning\", \"line4\": \"\", \"title\": {\"text\": \"Build Your Future with Besmak\", \"style\": {\"color\": \"#000000\", \"fontSize\": \"36px\", \"textAlign\": \"center\", \"fontWeight\": \"500\", \"lineHeight\": \"1.2\"}}, \"paragraphs\": [{\"id\": \"p1\", \"text\": \"We offer an opportunity for continuous learning and growth. Our success lies in total employee involvement. We are in the path of building a strong TQM / TPM culture. Our diverse manufacturing operations from Tooling, Moulding, Assembly to final product build offers an exciting opportunity for learning\", \"style\": {\"color\": \"#4B5563\", \"fontSize\": \"18px\", \"textAlign\": \"left\", \"fontWeight\": \"400\", \"lineHeight\": \"32px\"}}]}', 2, 1, '2026-03-12 10:11:04', '2026-03-13 07:53:10'),
