('cnh-capabilities-section', 'cnh-moulds', 'cnh-capabilities', '{\"title\": \"Our Core Capabilities\", \"capabilities\": [{\"icon\": \"Settings\", \"title\": \"High-Volume Production\", \"description\": \"Expertise in producing molds weighing up to 450 tons with an annual capacity of 150 tools.\"}, {\"icon\": \"Layers\", \"title\": \"Cavity versatility\", \"description\": \"Ranging from single cavity to 64 cavity molds, including family molds with up to 70% weight difference.\"}, {\"icon\": \"Box\", \"title\": \"Advanced Molding\", \"description\": \"Deep experience in 65% GF molds, insert molding, and over-molding technologies.\"}, {\"icon\": \"ShieldCheck\", \"title\": \"Precision Components\", \"description\": \"Specialized manufacturing of high-standard threaded components for various industries.\"}]}', 1, 1, '2026-03-13 07:12:02', '2026-03-13 07:12:02'),
('cnh-cta-id45', 'cnh-moulds', 'cnh-cta', '{}', 10, 1, '2026-03-16 13:41:33', '2026-03-16 13:41:33'),
('cnh-design-section', 'cnh-moulds', 'cnh-design', '{\"title\": \"Advanced Manufacturing & Software\", \"software\": [{\"name\": \"NX 11\", \"description\": \"High-precision CAD/CAM solution for complex tool engineering.\"}, {\"name\": \"WORKXPLORE\", \"description\": \"Advanced 3D visualization and analysis for design optimization.\"}, {\"name\": \"AutoCAD\", \"description\": \"Industry-standard drafting for detailed project planning.\"}, {\"name\": \"Delcam\", \"description\": \"Precision software for advanced toolpath generation.\"}], \"description\": \"We leverage industry-leading software solutions for design, simulation, and precision machining, supported by a dedicated team of engineering experts.\", \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/118443.jpg\"}', 3, 1, '2026-03-13 07:12:02', '2026-03-16 13:13:32'),
('cnh-hero-section', 'cnh-moulds', 'cnh-hero', '{\"title\": \"CNH Moulds – Precision, Innovation, and Excellence\", \"description\": \"Specializing in the design and manufacturing of high-precision molds tailored for connectors and engineering components. We bring cutting-edge solutions to industries that demand accuracy and durability.\", \"backgroundImage\": \"\", \"backgroundVideo\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/cnh-moulds-videos.mp4\"}', 0, 1, '2026-03-13 07:12:02', '2026-03-17 06:01:56'),
('cnh-infrastructure-section', 'cnh-moulds', 'cnh-infrastructure', '{\"title\": \"State-of-the-Art Infrastructure\", \"machines\": [{\"qty\": 3, \"name\": \"CNC Milling\", \"description\": \"Ensuring high-precision machining for complex molds.\"}, {\"qty\": 10, \"name\": \"EDM & Wire EDM\", \"description\": \"Providing intricate detailing and superior surface finishes.\"}, {\"qty\": 7, \"name\": \"Surface Grinding\", \"description\": \"Delivering high-accuracy finishing for mold components.\"}, {\"qty\": 2, \"name\": \"Cylindrical Grinding & Lathe\", \"description\": \"Enabling precision turning and specialized grinding.\"}, {\"qty\": 2, \"name\": \"CMM & VMM\", \"description\": \"Precise measurements and advanced quality control.\"}], \"description\": \"Our new 20,000 sq. ft. facility, inaugurated in January 2024, is designed to support high-precision mold manufacturing with the latest advancements in technology.\"}', 2, 1, '2026-03-13 07:12:02', '2026-03-13 07:12:02'),
('cnh-materials-section', 'cnh-moulds', 'cnh-materials', '{\"title\": \"Premium-Grade Tool Steels\", \"steels\": [{\"name\": \"C45 & P20\", \"description\": \"Medium-carbon and pre-hardened steels ideal for high-strength molds.\"}, {\"name\": \"1.2344 ESR\", \"description\": \"Hot-work steel known for superior heat resistance and toughness.\"}, {\"name\": \"Orvar Supreme\", \"description\": \"Premium grade with excellent polishability for high-demand tools.\"}, {\"name\": \"Calmax & Unimax\", \"description\": \"Cold-work steels with outstanding wear and impact resistance.\"}, {\"name\": \"Elmax\", \"description\": \"Premium stainless tool steel offering elite corrosion protection.\"}], \"description\": \"We use only the finest tool steels ensuring exceptional strength, wear resistance, and longevity for high-stress applications.\"}', 4, 1, '2026-03-13 07:12:02', '2026-03-13 07:12:02'),
('cnh-products-section', 'cnh-moulds', 'cnh-products', '{\"title\": \"Automotive Product Excellence\", \"oemTitle\": \"Trusted by Global OEMs\", \"products\": [{\"name\": \"2-Wheeler Connectors & Cluster Parts\"}, {\"name\": \"Fuel System Parts & Reservoir Tanks\"}, {\"name\": \"4-Wheeler Plastic Pedals\"}, {\"name\": \"Plastic Fastening Clips\"}], \"segments\": [{\"brands\": [\"Hero\", \"Suzuki\", \"Royal Enfield\", \"TVS\"], \"category\": \"2-Wheeler\"}, {\"brands\": [\"Tata\", \"Honda\", \"Hyundai\"], \"category\": \"4-Wheeler\"}, {\"brands\": [\"Tata\", \"KIA\"], \"category\": \"Heavy & EV Vehicle\"}], \"oem1Logo1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Hero_MotoCorp-Logo.wine.svg\", \"oem1Logo2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Suzuki_logo_2025_%28vertical%29.svg.png\", \"oem1Logo3\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/royal-enfield6316.jpg\", \"oem1Logo4\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/TVS-Motor-Logo.jpg\", \"oem2Logo1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Tata-Group-logo-3840x2160.png\", \"oem2Logo2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Hyundai-Logo-2011.png\", \"oem2Logo3\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Honda_Logo.svg.png\"}', 5, 1, '2026-03-13 07:12:02', '2026-03-16 13:22:25'),
('cnh-team-section', 'cnh-moulds', 'cnh-team', '{\"title\": \"Our 122-Member Team Strength\", \"description\": \"Our team consists of experts across Operations, Design, Quality, Planning, and Sales, ensuring efficiency and innovation in every mold we deliver.\", \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/124515.jpg\"}', 6, 1, '2026-03-13 07:12:02', '2026-03-16 13:31:25'),
('cnh-why-choose-us-section', 'cnh-moulds', 'cnh-why-choose-us', '{\"usps\": [{\"icon\": \"Target\", \"title\": \"Precision Engineering\", \"description\": \"Our molds are crafted with the highest level of accuracy for superior performance.\"}, {\"icon\": \"Lightbulb\", \"title\": \"Tailored Innovation\", \"description\": \"Years of experience allowing us to deliver industry-specific solutions.\"}, {\"icon\": \"TrendingUp\", \"title\": \"Scalable Excellence\", \"description\": \"From small batches to large-scale production, we cater to all sizes.\"}], \"title\": \"Why Choose CNH Moulds?\"}', 7, 1, '2026-03-13 07:12:02', '2026-03-13 07:12:02'),
('company-overview-detailed-1', 'about-page', 'company-overview-detailed', '{\"topTitle\": \"COMPANY OVERVIEW\", \"mainTitle\": \"Company Overview\", \"strength1\": \"100% revenue is from Automobile Industry\", \"strength2\": \"Strong Presence in the Wiring harnesses supply chain\", \"strength3\": \"BESMAK is a preferred source for OEMs for indigenisation and development\", \"strength4\": \"QMS is certified in accordance with IATF16949 in 2016\", \"strength5\": \"Total Number of Employees — 460\", \"strength6\": \"One part under Patent application\", \"strength7\": \"We prioritise delivery, flexibility and customer satisfaction in all our services\", \"strength8\": \"We focus on new product development, ensuring quality while maintaining cost efficiency\", \"component1\": \"Automobile Connection System\", \"component2\": \"Terminals\", \"component3\": \"Wiring Harness Components\", \"component4\": \"High Precision Plastic Components\", \"component5\": \"Injection Moulds\", \"component6\": \"High Speed Stamping Tools\", \"stat1Label\": \"YEARS OF EXCELLENCE\", \"stat1Value\": \"30+\", \"stat2Label\": \"EMPLOYEES\", \"stat2Value\": \"460\", \"stat3Label\": \"PARTS PER DAY\", \"stat3Value\": \"3.2M\", \"overviewImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/at%20a%20glance%20600x800%20.png\", \"strengthsTopTitle\": \"KEY STRENGTHS OF BESMAK\", \"componentsSubtitle\": \"Expert in Manufacturing Wide Range of Components:\", \"strengthsMainTitle\": \"Key Strengths of Besmak\"}', 3, 1, '2026-03-12 09:45:18', '2026-03-17 12:09:50'),
('core-team-hero-1', 'core-team-page-id', 'core-team-hero', '{\"title\": \"Core Team\", \"bgImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/89051.jpg\", \"description\": \"Meet the experts driving our engineering excellence and manufacturing innovation.\"}', 1, 1, '2026-03-17 08:51:52', '2026-03-17 10:06:22'),
('core-team-members-1', 'core-team-page-id', 'core-team-members', '{\"title\": \"Meet Our Core Team\", \"categories\": [{\"icon\": \"award\", \"title\": \"Leadership\", \"members\": [{\"name\": \"Hema Hari\", \"designation\": \"Managing Director\"}, {\"name\": \"Rajesh R\", \"designation\": \"Director\"}]}, {\"icon\": \"users\", \"title\": \"Senior Management\", \"members\": [{\"name\": \"BRM Rao\", \"designation\": \"Chief Operating Officer (COO)\"}, {\"name\": \"Senthilnath P K\", \"designation\": \"Vice President – Technical\"}, {\"name\": \"Kannan M\", \"designation\": \"Quality DGM\"}, {\"name\": \"Vinod Kumar\", \"designation\": \"HR & Admin HOD\"}]}, {\"icon\": \"layers\", \"title\": \"Functional & Divisional Heads\", \"members\": [{\"name\": \"Singaravelu\", \"designation\": \"Finance Head\"}, {\"name\": \"Ramprasath\", \"designation\": \"ED Divisional Head\"}, {\"name\": \"Rama Kuladeep\", \"designation\": \"CS Divisional Head\"}, {\"name\": \"Sudeep\", \"designation\": \"Stamping Divisional Head\"}]}, {\"icon\": \"settings\", \"title\": \"Operations & Department Leads\", \"members\": [{\"name\": \"Durairaj\", \"designation\": \"Accounts\"}, {\"name\": \"Ravindran K\", \"designation\": \"IT & Digitalization\"}, {\"name\": \"Sivakumar R\", \"designation\": \"Purchase / Stores HOD\"}, {\"name\": \"Navaneetha Krishnan\", \"designation\": \"Production / PPC / Maintenance HOD\"}]}, {\"icon\": \"tool\", \"title\": \"Technical & Engineering Team\", \"members\": [{\"name\": \"Aba Samuel\", \"designation\": \"Technical Expert (Connector)\"}, {\"name\": \"Rangarajan S\", \"designation\": \"E & D Product Design HOD\"}, {\"name\": \"Ranjith Kumar\", \"designation\": \"PMG Sr. Manager\"}, {\"name\": \"Suresh\", \"designation\": \"Tool Room GM\"}]}], \"member_1_1_bio\": \"This is the demo BIO\", \"member_1_1_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_1_2_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_2_1_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_2_2_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_2_3_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_2_4_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_3_1_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_3_2_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_3_3_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_3_4_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_4_1_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_4_2_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_4_3_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_4_4_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_5_1_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_5_2_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_5_3_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_5_4_image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/145856997_296fe121-5dfa-43f4-98b5-db50019738a7.svg\", \"member_1_1_linkedin\": \"#\", \"member_1_2_linkedin\": \"#\", \"member_2_1_linkedin\": \"#\", \"member_2_2_linkedin\": \"#\", \"member_2_3_linkedin\": \"#\", \"member_2_4_linkedin\": \"#\", \"member_3_1_linkedin\": \"#\", \"member_3_2_linkedin\": \"#\", \"member_3_3_linkedin\": \"#\", \"member_3_4_linkedin\": \"#\", \"member_4_1_linkedin\": \"#\", \"member_4_2_linkedin\": \"#\", \"member_4_3_linkedin\": \"#\", \"member_4_4_linkedin\": \"#\", \"member_5_1_linkedin\": \"#\", \"member_5_2_linkedin\": \"#\", \"member_5_3_linkedin\": \"#\", \"member_5_4_linkedin\": \"#\"}', 3, 1, '2026-03-17 08:51:52', '2026-03-17 11:22:35'),
('core-team-overview-1', 'core-team-page-id', 'core-team-overview', '{\"title\": \"The Minds Behind Our Engineering Excellence\", \"bgImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/2981.jpg\", \"tagline\": \"Our Core Team\", \"description\": \"At Besmak Components Pvt. Ltd., our strength lies in the expertise, vision, and dedication of our core team. Built on a foundation of technocrats and industry professionals, our leadership brings together decades of experience in automotive component manufacturing, tool design, and precision engineering.\\n\\nFrom strategy to execution, our team plays a critical role in driving innovation, ensuring operational excellence, and delivering consistent value to our customers.\", \"section1Desc\": \"Founded by industry experts with deep knowledge in injection mould design and manufacturing, Besmak has grown under strong leadership that emphasizes customer relationships, technical excellence, and long-term growth.\\n\\nOur leaders continue to guide the organization with a forward-thinking approach, adapting to evolving automotive trends including electric vehicle components and advanced connectivity solutions.\", \"section2Desc\": \"Driven by a shared commitment to quality, our leadership ensures that every project is executed with precision—from concept to delivery.\\n\\nBy working closely with customers and partners, the core team ensures seamless project execution, reliable supply, and solutions tailored to evolving industry needs.\", \"section1Title\": \"Leadership with Vision and Experience\", \"section2Title\": \"Committed to Quality and Customer Success\"}', 2, 1, '2026-03-17 08:51:52', '2026-03-17 10:45:06'),
('cs-achievements-section', 'connection-systems', 'cs-achievements', '{\"image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/pexels-sejio402-6636458.jpg\", \"title\": \"Achievements\", \"achievements\": [\"Preferred supplier for multiple leading automotive OEMs.\", \"Developed high-voltage connectors for EV and charging applications.\", \"Applied patents for innovative connection system products.\", \"NABL-accredited testing lab aligned with global quality standards.\", \"Product design and development capabilities including 3D prototyping.\", \"Recognized as a \\\"Great Place to Work\\\" for fostering employee development.\"]}', 5, 1, '2026-03-12 12:52:38', '2026-03-13 09:19:43'),
('cs-capabilities-section', 'connection-systems', 'cs-capabilities', '{\"title\": \"Our Capabilities\", \"subtitle\": \"We offer a comprehensive range of advanced manufacturing solutions designed to meet complex customer requirements:\", \"capabilities\": [{\"icon\": \"Boxes\", \"title\": \"Expertise in Precision Molding\", \"description\": \"Our core strength lies in precision molding, including insert molding, over-molding, and plastic threaded parts molding. We handle machines ranging from 40 to 450 tons.\"}, {\"icon\": \"Settings\", \"title\": \"Versatility in Molding Solutions\", \"description\": \"Spanning from single-cavity to 64-cavity molds. We are adept at producing family molds with up to 70% weight difference.\"}, {\"icon\": \"Cpu\", \"title\": \"Advanced Material Handling\", \"description\": \"Experienced in processing engineering-grade thermoplastics and high-performance materials, including up to 65% Glass Filled (GF) plastics, PPS, PA66, LCP.\"}, {\"icon\": \"TrendingUp\", \"title\": \"High-Volume Production\", \"description\": \"With the ability to produce up to 3 million parts per day and 30 lakh connector parts daily, our production capacity is built for scale.\"}, {\"icon\": \"Zap\", \"title\": \"Automated Assembly & Quality Assurance\", \"description\": \"We integrate advanced technologies such as robotic part insertion, poke yoke systems, and automated assembly machines to ensure error-free production.\"}]}', 2, 1, '2026-03-12 12:52:38', '2026-03-12 12:52:38'),
('cs-hero-section', 'connection-systems', 'cs-hero', '{\"title\": \"Connection Systems Division\", \"ctaText\": \"Explore Products \", \"subtitle\": \"Precision in Every Connection\", \"backgroundImage\": \"\", \"backgroundVideo\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak%20Connectors%20.mp4\"}', 0, 1, '2026-03-12 12:52:38', '2026-03-17 05:57:26'),
('cs-infrastructure-section', 'connection-systems', 'cs-infrastructure', '{\"items\": [{\"icon\": \"Factory\", \"title\": \"State-of-the-Art Plants\", \"description\": \"Three manufacturing facilities — two in Chennai (Orgadam) and one in Sanand, Gujarat — with over 100,000 sq. ft. floor space.\"}, {\"icon\": \"Cog\", \"title\": \"Advanced Machinery\", \"description\": \"69 injection molding machines (40 to 450 tons) and stamping presses (15 to 110 tons). All machines supported by OEE monitoring and SAP workflows.\"}, {\"icon\": \"Battery\", \"title\": \"Reliable Power Systems\", \"description\": \"80% renewable energy and 100% UPS back-up, ensuring uninterrupted production.\"}, {\"icon\": \"FlaskConical\", \"title\": \"World-Class Testing\", \"description\": \"DVP Lab performing 51 out of 52 tests, NABL-accredited. IATF 16949:2016, ISO 14001:2015, SQ Mark, and MACE certified.\"}], \"title\": \"Infrastructure & Manufacturing Facilities\"}', 3, 1, '2026-03-12 12:52:38', '2026-03-12 12:52:38'),
('cs-overview-section', 'connection-systems', 'cs-overview', '{\"title\": \"Overview\", \"image1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/chgfdh.png\", \"image2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/8MW-090-FHCL-G-BL-With-Clip-Assy-image.jpg\", \"description\": \"The Connection Systems Division of Besmak Components Pvt Ltd is a leading manufacturer of precision connectors and engineering components, catering to the rapidly evolving needs of the automotive and industrial sectors. With over three decades of domain expertise, we specialize in delivering high-quality, reliable, and technologically advanced connection systems that meet stringent global standards.\\n\\nOur division is built on a strong foundation of technical excellence, world-class infrastructure, and an unwavering commitment to customer satisfaction. As a preferred partner to leading OEMs, we support their growth with superior products, scalable manufacturing, and continuous innovation.\"}', 1, 1, '2026-03-12 12:52:38', '2026-03-18 08:45:34'),
('cs-products-section', 'connection-systems', 'cs-products', '{\"title\": \"Product Range\", \"products\": [\"Sealed and Unsealed Connectors\", \"SMT Connectors\", \"Headers and Wire Seals\", \"Terminals, Clips, Caps, and Cable Tags\", \"Hybrid and Relay Connectors\"], \"segments\": \"Our products cater to leading automotive OEMs across 2-wheeler, 4-wheeler, and electric vehicle (EV) segments such as Hero, Suzuki, Royal Enfield, TVS, Bajaj, Honda, Tata, Hyundai, Kia, Ola, Ather, and more.\", \"segmentsTitle\": \"End-Use Segments\", \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/52159.jpg\"}', 4, 1, '2026-03-12 12:52:38', '2026-03-13 12:56:53'),
('cs-why-choose-us-section', 'connection-systems', 'cs-why-choose-us', '{\"title\": \"Why Choose Us?\", \"advantages\": [{\"title\": \"Decades of Experience & Industry Leadership\", \"description\": \"With over 30 years of expertise in connection systems, we understand the evolving needs of the automotive industry and proactively innovate to meet them.\"}, {\"title\": \"End-to-End Capabilities\", \"description\": \"From concept to delivery, our comprehensive capabilities in product design, tooling, prototyping, production, and quality validation make us a one-stop partner for customers.\"}, {\"title\": \"Focus on Innovation\", \"description\": \"We invest continuously in R&D, automation, and digitalization to enhance product performance and manufacturing efficiency. Our ability to process advanced materials and develop complex components gives us a competitive edge.\"}, {\"title\": \"Commitment to Quality & Compliance\", \"description\": \"Our products meet global quality benchmarks, backed by industry certifications and advanced testing infrastructure. We deliver zero-defect, high-precision components at scale.\"}, {\"title\": \"Sustainable Manufacturing\", \"description\": \"We leverage renewable energy and adopt eco-friendly manufacturing practices, reflecting our commitment to responsible business growth.\"}, {\"title\": \"Customer-Centric Approach\", \"description\": \"We work closely with leading OEMs, aligning our growth with their success. Our dedicated team ensures on-time delivery, customized solutions, and continuous process improvement.\"}], \"description\": \"At Besmak Components Pvt Ltd, we don’t just manufacture connectors — we build lasting partnerships based on trust, quality, and performance. Here’s why we are the preferred choice:\"}', 6, 1, '2026-03-12 12:52:38', '2026-03-13 06:22:18'),
('csr-banner-1', 'csr-page', 'csr-banner', '{\"alt\": \"CSR Banner\", \"image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/CSR-Banner.jpg\"}', 1, 1, '2026-03-17 05:31:43', '2026-03-18 12:41:57'),
('csr-community-1', 'csr-page', 'csr-community', '{\"title\": \"Community Development\", \"subtitle\": \"Empowering People, Building Livelihoods\", \"point1Desc\": \"Providing platforms to promote and sell products made by intellectually challenged individuals, supporting their livelihood\", \"point2Desc\": \"Provided essential support during major natural disasters, contributing significant relief and rehabilitation efforts to affected regions.\", \"stat1Label\": \"Chennai Floods\", \"stat1Value\": \"2015\", \"stat2Label\": \"Kerala Floods\", \"stat2Value\": \"2018\", \"stat3Label\": \"Committed to\", \"stat3Value\": \"Relief\", \"description\": \"We are committed to supporting communities and creating inclusive growth opportunities.\", \"point1Title\": \"Support for Differently-Abled Individuals\", \"point2Title\": \"Disaster Relief Initiatives\"}', 6, 1, '2026-03-19 11:50:52', '2026-03-19 11:50:52'),
('csr-grid-1', 'csr-page', 'csr-grid', '{\"item1Desc\": \"At Besmak, we are eco friendly and caring for environment by our green initiatives. On the whole, 40% of our power requirements are met through Solar & Wind energy.\", \"item2Desc\": \"Under its environmental CSR initiatives, since 2014, BESMAK Components Pvt Ltd has been undertaking steps like initiating tree plantation drives across its campuses.\", \"mainTitle\": \"Think Green, Go Green...\", \"item1Image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/CSR-Banner.jpg\", \"item1Title\": \"Solar & Wind Energy\", \"item2Image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/CSR-Banner.jpg\", \"item2Title\": \"Tree saplings\"}', 2, 1, '2026-03-17 08:04:08', '2026-03-17 08:14:46'),
('csr-healthcare-1', 'csr-page', 'csr-healthcare', '{\"title\": \"Healthcare & Social Support\", \"subtitle\": \"Supporting Lives and Communities\", \"point1Desc\": \"Organized regularly in association with organizations like Lions Club, with active employee participation\", \"point2Desc\": \"Donation of a dialysis machine to hospitals through Rotary Club, helping provide affordable treatment to patients in need\", \"point3Desc\": \"Collaboration with philanthropic healthcare institutions offering free or subsidized treatment\", \"stat1Label\": \"Partner\", \"stat1Value\": \"Rotary Club\", \"stat2Label\": \"Partner\", \"stat2Value\": \"Lions Club\", \"stat3Label\": \"Care Model\", \"stat3Value\": \"Subsidized\", \"description\": \"We actively contribute to healthcare and social welfare initiatives to improve the quality of life in our communities.\", \"point1Title\": \"Blood Donation Camps\", \"point2Title\": \"Medical Support Initiatives\", \"point3Title\": \"Support for Medical Institutions\"}', 5, 1, '2026-03-19 11:26:11', '2026-03-19 11:26:11'),
('csr-initiatives-1', 'csr-page', 'csr-initiatives', '{\"image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/CSR-Initiatives-Landscape.png\", \"heading\": \"OUR KEY INITIATIVES\", \"item1Desc\": \"At Besmak, we are eco friendly and caring for environment by our green initiatives. On the whole, 40% of our power requirements are met through Solar & Wind energy.\", \"item2Desc\": \"Under its environmental CSR initiatives, since 2014, BESMAK Components Pvt Ltd has been undertaking steps like initiating tree plantation drives across its campuses.\", \"item1Title\": \"Solar & Wind Energy\", \"item2Title\": \"Tree saplings\"}', 3, 1, '2026-03-17 13:56:36', '2026-03-20 11:07:30'),
('dual-cards-home', 'home-page-id', 'dual-cards-section', '{\"leftCard\": \"{\\\"title\\\":\\\"CSR Activities\\\",\\\"description\\\":\\\"At Besmak, we believe that true progress goes beyond manufacturing excellence. While we are proud to contribute to the automobile component industry through high-quality connectors, terminals and precision components, we also remain deeply committed to giving back to the community that supports our growth.\\n\\nWe strongly believe that responsible business is built on compassion, sustainability and shared growth. Through continuous CSR initiatives, Besmak strives to build healthier communities, support those in need and contribute towards a better tomorrow.\\\",\\\"link\\\":\\\"/csr\\\",\\\"buttonText\\\":\\\"Read More\\\"}\", \"rightCard\": \"{\\\"title\\\":\\\"Career Opportunities at Besmak\\\",\\\"description\\\":\\\"At Besmak, we believe our people are the driving force behind everything we achieve. We are committed to building a workplace where talent is valued, growth is encouraged and every individual has the opportunity to make a meaningful impact.\\n\\nWhether you are an experienced professional or a passionate fresher ready to begin your journey, Besmak offers a supportive environment that promotes learning, teamwork and long-term career development.\\n\\nJoin us and be a part of a company where innovation, responsibility and shared success go hand in hand.\\\",\\\"link\\\":\\\"/careers\\\",\\\"buttonText\\\":\\\"Join Us\\\"}\"}', 8, 1, '2026-03-05 11:58:39', '2026-03-05 11:58:39'),
('ecosystem-integration-1', '7dnzxaec4p2', 'ecosystem-integration', '{\"oems\": [{\"name\": \"Tata Motors\"}, {\"name\": \"Hyundai\"}, {\"name\": \"Honda\"}, {\"name\": \"Suzuki\"}, {\"name\": \"Mahindra\"}, {\"name\": \"Toyota\"}, {\"name\": \"Ford\"}], \"title\": \"OEM & Tier-1 Ecosystem Integration\", \"description\": \"Besmak plays a vital role in the automotive supply chain by working closely with Tier-1 wiring harness manufacturers and system integrators, who in turn supply major automotive brands.\"}', 4, 1, '2026-03-18 07:10:13', '2026-03-18 07:10:13'),
('engineering-collaboration-1', '7dnzxaec4p2', 'engineering-collaboration', '{\"title\": \"Engineering Collaboration & Co-Development\", \"points\": [{\"title\": \"Joint product design and development\", \"description\": \"Collaborating from the early stages of product development to ensure optimal design.\"}, {\"title\": \"Tooling and prototyping support\", \"description\": \"Rapid prototyping and specialized tool design for new automotive applications.\"}, {\"title\": \"Custom solutions for complex automotive applications\", \"description\": \"Engineering tailor-made components for unique requirements.\"}, {\"title\": \"Continuous improvement through feedback and innovation\", \"description\": \"Constantly evolving based on customer feedback and industry trends.\"}], \"description\": \"Our partnerships go beyond supply—we actively collaborate with customers from the early stages of product development.\"}', 5, 1, '2026-03-18 07:10:15', '2026-03-18 07:10:15'),
('ep-about-section', 'engineering-products', 'ep-about', '{\"image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak-product-engineering.png\", \"title\": \"About Us\", \"description\": \"At Besmak’s Engineering Products Division, we specialize in delivering precision-engineered plastic components that power India’s growing auto component manufacturing sector. With a focus on high-quality, high-performance solutions, we offer end-to-end manufacturing capabilities to meet the evolving needs of the automotive and industrial markets.\"}', 1, 1, '2026-03-13 06:41:01', '2026-03-18 09:56:03');
INSERT INTO `page_sections` (`id`, `pageId`, `type`, `content`, `sortOrder`, `isActive`, `createdAt`, `updatedAt`) VALUES
('ep-capabilities-section', 'engineering-products', 'ep-capabilities', '{\"title\": \"Our Capabilities\", \"capabilities\": [{\"icon\": \"Settings\", \"title\": \"Manufacturing Excellence\", \"details\": [\"In-house tool design & building\", \"Prototype molding services\", \"3D printing for rapid prototyping\", \"ISO 8 Clean Room (EV products Focus)\", \"Advanced high-magnification image analysis\"], \"description\": \"Comprehensive solutions including insert molding, overmolding, and plastic threaded parts molding using engineering-grade thermoplastics.\"}, {\"icon\": \"FlaskConical\", \"title\": \"Raw Material Expertise\", \"details\": [\"Rigorous raw material verification\", \"Moisture analysis\", \"Melt Flow Index (MFI) testing\"], \"description\": \"Processing engineering-grade thermoplastics like LDPE, PPS, talc-filled, and glass-filled materials (15% to 65% content).\"}, {\"icon\": \"Zap\", \"title\": \"Value-Added Processes\", \"details\": [\"Ultrasonic & Resistance welding\", \"Pad printing & Laser marking\", \"Air leak, Continuity & Hi-pot testing\", \"Barcode-based complete reverse traceability\"], \"description\": \"Custom-designed Special Purpose Machines (SPMs) and advanced assembly techniques.\"}]}', 2, 1, '2026-03-13 06:41:01', '2026-03-13 06:41:01'),
('ep-commitment-section', 'engineering-products', 'ep-commitment', '{\"title\": \"Our Commitment\", \"description\": \"With a strong technical foundation, modern infrastructure, and skilled workforce, the Engineering Products Division is focused on driving innovation, ensuring operational excellence, and supporting customer growth.\"}', 7, 1, '2026-03-13 06:41:01', '2026-03-13 06:41:01'),
('ep-hero-section', 'engineering-products', 'ep-hero', '{\"title\": \"Engineering Products Division\", \"tagline\": \"Precision. Performance. Innovation.\", \"backgroundImage\": \"\", \"backgroundVideo\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak%20Engineering%20Products%20.mp4\"}', 0, 1, '2026-03-13 06:41:01', '2026-03-17 06:00:19'),
('ep-infrastructure-section', 'engineering-products', 'ep-infrastructure', '{\"image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/maxresdefault.jpg\", \"items\": [{\"size\": \"30,000 sq. ft.\", \"title\": \"Plant 1\", \"location\": \"Orgadam, Chennai\"}, {\"size\": \"40,000 sq. ft.\", \"title\": \"Plant 2\", \"location\": \"Sanand, Gujarat\"}, {\"size\": \"30,000 sq. ft.\", \"title\": \"Plant 3 (Upcoming)\", \"location\": \"Orgadam, Chennai (April 2025)\"}], \"title\": \"Infrastructure & Facilities\", \"techTitle\": \"Advanced Machinery\", \"description\": \"Our manufacturing infrastructure includes modern, fully equipped facilities strategically located across India\'s industrial hubs.\", \"item1Location\": \"Chennai, Tamil Nadu\", \"techDescription\": \"Modern horizontal and vertical molding machines ranging from 40 to 450 tons, equipped with 3-Axis robots supporting dual-side access for rapid part handling.\"}', 3, 1, '2026-03-13 06:41:01', '2026-03-18 10:18:58'),
('ep-products-section', 'engineering-products', 'ep-products', '{\"title\": \"Product Segments\", \"segments\": [{\"name\": \"FSM\"}, {\"name\": \"ECU\"}, {\"name\": \"Cluster\"}, {\"name\": \"APS\"}, {\"name\": \"Wiring Harness Channels\"}, {\"name\": \"Latch & Actuator Systems\"}, {\"name\": \"Connector Accessories\"}, {\"name\": \"Bus bar overmolding components\"}, {\"name\": \"EV products\"}], \"industriesTitle\": \"End-Use Industries\", \"industriesDescription\": \"Our products are supplied to leading four-wheeler and two-wheeler manufacturers, contributing to India’s leadership in the global auto components industry.\"}', 5, 1, '2026-03-13 06:41:01', '2026-03-13 06:41:01'),
('ep-quality-section', 'engineering-products', 'ep-quality', '{\"title\": \"Quality & Metrology\", \"labItems\": [{\"name\": \"Zeiss CMM\", \"description\": \"World-class coordinate measuring machine for sub-micron accuracy.\"}, {\"name\": \"VMM with Programmable Probes\", \"description\": \"Automated vision measuring system for precise geometry check.\"}, {\"name\": \"Advanced Roughness Testers\", \"description\": \"Precise surface finish analysis for high-performance parts.\"}], \"description\": \"We follow stringent quality assurance practices supported by advanced metrology systems, ensuring dimensional accuracy and product reliability.\", \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Quality-Metrology.jpg\"}', 4, 1, '2026-03-13 06:41:01', '2026-03-16 07:31:59'),
('ep-why-choose-us-section', 'engineering-products', 'ep-why-choose-us', '{\"title\": \"Why Choose Us\", \"points\": [{\"title\": \"Proven Expertise\", \"description\": \"Deep domain knowledge in precision molding and component manufacturing.\"}, {\"title\": \"End-to-End Solutions\", \"description\": \"Complete production capabilities from prototyping to full-scale manufacturing.\"}, {\"title\": \"Quality Assurance\", \"description\": \"Robust quality systems, traceability processes, and certified testing facilities.\"}, {\"title\": \"Material Expertise\", \"description\": \"Specialized in handling engineering-grade thermoplastics and high-performance materials.\"}, {\"title\": \"Future-Ready Infrastructure\", \"description\": \"State-of-the-art manufacturing facilities with continuous upgrades.\"}, {\"title\": \"Customer Focus\", \"description\": \"Strong emphasis on reliability, speed, and building long-term partnerships.\"}], \"description\": \"At Besmak’s Engineering Products Division, we are committed to delivering value beyond manufacturing. Here’s what sets us apart:\"}', 6, 1, '2026-03-13 06:41:01', '2026-03-13 06:41:01'),
('events-achievements-section', 'home-page-id', 'events-achievements', '{\"title\": \"Events & Achievements\", \"events\": \"[{\\\"id\\\":\\\"1\\\",\\\"image\\\":\\\"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak%20suspa%20supplier%20award%202025.png\\\",\\\"alt\\\":\\\"Award ceremony\\\"},{\\\"id\\\":\\\"2\\\",\\\"image\\\":\\\"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Container-1.png\\\",\\\"alt\\\":\\\"Exhibition stall\\\"},{\\\"id\\\":\\\"3\\\",\\\"image\\\":\\\"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Container-2.png\\\",\\\"alt\\\":\\\"Exhibition stall 2\\\"},{\\\"id\\\":\\\"4\\\",\\\"image\\\":\\\"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Yazaki%20Kaizen%20Award%20Post.png\\\",\\\"alt\\\":\\\"Product showcase\\\"}]\", \"caption\": \"COMPANY MILESTONES\", \"description\": \"Key milestones, celebrations and initiatives highlighting our continued growth and commitment to excellence.\"}', 7, 1, '2026-03-05 11:51:20', '2026-03-12 05:09:18'),
('founders-message-1', 'about-page', 'founders-message', '{\"name\": \"C.N. Hari\", \"para1\": \"A technocrat with rich experience in Product Design & Tool Manufacturing, Mr. C.N. Hari founded Besmak Components Pvt. Ltd. in 1994 with a singular vision: to build an Indian manufacturing company that competes on the global stage through engineering excellence.\", \"para2\": \"What started as a connector business in 1989 has evolved into a multi-vertical, IATF 16949-certified enterprise — with state-of-the-art facilities across Chennai, Ahmedabad, Pune, and Delhi, producing over 3.2 million precision components each day.\", \"para3\": \"Under his leadership, Besmak has secured certifications from Maruti MACE (Green Supplier), Hyundai Motor India, and NABL accreditation for our in-house testing laboratory — setting new benchmarks for quality in the automotive supply chain.\", \"quote\": \"From a single-room tool design studio in 1987 to a ₹259 Crore manufacturing powerhouse — our journey is proof that precision, persistence and passion can build world-class institutions.\", \"badge1\": \"Product Design Expert\", \"badge2\": \"Tool Manufacturing\", \"badge3\": \"IATF 16949 Leadership\", \"badge4\": \"30+ Years Industry Experience\", \"imageUrl\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/CN%20Hari%20-%20Besmak%20Founder%20-%20Image%20%281%29.png\", \"topTitle\": \"LEADERSHIP\", \"mainTitle\": \"About Founder\", \"founderRole\": \"Founder Chairman & Managing Director\"}', 4, 1, '2026-03-12 11:31:54', '2026-03-18 08:41:19'),
('global-network-1', '7dnzxaec4p2', 'global-network', '{\"areas\": [{\"icon\": \"🚗\", \"title\": \"Two-wheeler and four-wheeler segments\"}, {\"icon\": \"⚡\", \"title\": \"Electric vehicle (EV) applications\"}, {\"icon\": \"📡\", \"title\": \"Advanced automotive electronics and connectivity systems\"}], \"title\": \"Global & Domestic Network\", \"description\": \"With a growing footprint across India and expanding global reach, Besmak supports customers across diverse segments and regions.\"}', 6, 1, '2026-03-18 07:10:16', '2026-03-18 07:10:16'),
('home-product-search', 'home', 'product-search', '{}', 100, 1, '2026-03-05 13:17:17', '2026-03-05 13:17:17'),
('industry-engagement-1', '7dnzxaec4p2', 'industry-engagement', '{\"items\": [{\"icon\": \"🏢\", \"title\": \"Automotive component ecosystems\"}, {\"icon\": \"🌐\", \"title\": \"Industry exhibitions and technical forums\"}, {\"icon\": \"💡\", \"title\": \"Technology and innovation networks\"}], \"title\": \"Industry Associations & Engagement\"}', 8, 1, '2026-03-18 07:10:18', '2026-03-18 07:10:18'),
('industry-leaders-1', '7dnzxaec4p2', 'industry-leaders', '{\"title\": \"Collaborating with Industry Leaders\", \"partners\": [{\"name\": \"Bosch\", \"iconType\": \"Cpu\"}, {\"name\": \"Aptiv\", \"iconType\": \"Zap\"}, {\"name\": \"Visteon\", \"iconType\": \"Gauge\"}, {\"name\": \"Hella\", \"iconType\": \"Zap\"}, {\"name\": \"Danfoss\", \"iconType\": \"Settings\"}, {\"name\": \"Yazaki\", \"iconType\": \"Component\"}, {\"name\": \"Motherson\", \"iconType\": \"Layers\"}, {\"name\": \"Minda Group\", \"iconType\": \"Settings\"}, {\"name\": \"Fujikura\", \"iconType\": \"Component\"}, {\"name\": \"TI Automotive\", \"iconType\": \"Car\"}, {\"name\": \"WABCO\", \"iconType\": \"Truck\"}, {\"name\": \"Kautex Textron\", \"iconType\": \"Database\"}], \"description\": \"We are proud to partner with globally recognized automotive and technology leaders, supporting their requirements in connectors, terminals, and precision components. Our key customers and partners include organizations such as:\"}', 3, 1, '2026-03-18 07:10:11', '2026-03-18 07:10:11'),
('news-section-home', 'home-page-id', 'news-section', '{\"title\": \"Key Highlights of Besmak\", \"images\": [{\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/1200x600jhgfgsd.png\", \"date\": \"\", \"title\": \"Legacy & Experience\"}, {\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/kjhgfsghjfds.png\", \"date\": \"\", \"title\": \"Workforce Strength\"}, {\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Products-1500.png\", \"date\": \"\", \"title\": \"Production Capability\"}, {\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/jhgfghdtfyd.png\", \"date\": \"\", \"title\": \"Technology & Quality\"}, {\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/ikuyftydrsesres.png\", \"date\": \"\", \"title\": \"600+ Moulds\"}, {\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Background-Image.jpg\", \"date\": \"\", \"title\": \"350+ Customers \"}], \"newsItems\": [{\"link\": \"#\", \"title\": \"Strong Manufacturing Expertise\", \"description\": \"Besmak is a globally preferred manufacturer specializing in automobile connection systems, wiring harness components, precision plastic parts, stamping tools, and injection moulds, supported by advanced manufacturing technologies.\"}, {\"link\": \"#\", \"title\": \"High Production Capability\", \"description\": \"The company has the capacity to produce over 3.2 million parts per day, supported by automated assembly lines, precision tooling, and digitally controlled manufacturing systems.\"}, {\"link\": \"#\", \"title\": \"Trusted by Global Automotive Clients\", \"description\": \"Besmak is a preferred partner for OEMs and plays a key role in the automotive wiring harness supply chain, providing high-quality and reliable components.\"}], \"clientLogos\": [{\"id\": \"logo-0\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/client13.png\"}, {\"id\": \"logo-1\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c18.png\"}, {\"id\": \"logo-2\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c17.png\"}, {\"id\": \"logo-3\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c16.png\"}, {\"id\": \"logo-4\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c15.png\"}, {\"id\": \"logo-5\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c14.png\"}, {\"id\": \"logo-6\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c12.png\"}, {\"id\": \"logo-7\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c11.png\"}, {\"id\": \"logo-8\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c10.png\"}, {\"id\": \"logo-9\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c9.png\"}, {\"id\": \"logo-10\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c8.png\"}, {\"id\": \"logo-11\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c7.png\"}, {\"id\": \"logo-12\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c6.png\"}, {\"id\": \"logo-13\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c5.png\"}, {\"id\": \"logo-14\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/c4.png\"}, {\"id\": \"logo-15\", \"alt\": \"\", \"src\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/3.png\"}], \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Key-Highlights.png\", \"featuredBoxText\": \"Besmak continues to achieve major milestones through technology upgrades, new product developments, automation, ESG initiatives, and global certifications, positioning itself as a future-ready manufacturing company.\"}', 3, 1, '2026-03-06 12:22:33', '2026-03-23 13:23:58'),
('our-presence-1', 'about-page', 'our-presence', '{\"title\": \"Our Presence\", \"subtitle\": \"OUR PRESENCE\", \"badgeText\": \"AFTER 2024 IMPLEMENTED\", \"loc1Image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Chennai_Central.jpg\", \"loc1Items\": \"Unit 1 (Oragadam): 40K sq. ft. to 60K sq. ft. under construction\\nWarehouse - I - 9K Sq. ft.\\nIn-House Validation Center\\nTool Room (Oragadam) - 17K Sq. ft\\nUnit - II (Athipet)\\nDesign Centre (Sakthi Towers)\\nUnit - IV under construction - 100K Sq. ft\", \"loc1Title\": \"Chennai\", \"loc2Image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/park-img.jpg\", \"loc2Items\": \"Unit-III (Sanand) 40K Sq. ft.\\nConnection Systems & EP Division\\nAvailable Capacity: 20K sq. ft\", \"loc2Title\": \"Ahmedabad\", \"loc3Image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Master.webp\", \"loc3Items\": \"Warehouse - II 10K Sq. ft.\\nServing West India OEM customers\", \"loc3Title\": \"Pune\", \"loc4Image\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Red-Fort-Old-Delhi-India.webp\", \"loc4Items\": \"Warehouse - III (Gurgaon) 12.5K Sq. ft.\\nServing North India OEM customers\", \"loc4Title\": \"Delhi\", \"description\": \"Manufacturing units, tool rooms, design centres and warehouses across Delhi, Ahmedabad, Pune and Chennai — serving the Indian automotive supply chain.\"}', 50, 1, '2026-03-12 12:25:33', '2026-03-17 10:11:10'),
('partnerships-hero-1', '7dnzxaec4p2', 'partnerships-hero', '{\"title\": \"Partnerships\", \"bgImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Partnerships-banner.jpg\", \"breadcrumbs\": [{\"url\": \"/\", \"label\": \"Home\"}, {\"label\": \"Discover Us\"}, {\"label\": \"Partnerships\"}]}', 1, 1, '2026-03-18 07:10:08', '2026-03-18 09:38:00'),
('partnerships-intro-1', '7dnzxaec4p2', 'partnerships-intro', '{\"image\": \"https://images.unsplash.com/photo-1552664730-d307ca884978?q=80&w=1200&auto=format&fit=crop\", \"stats\": [{\"icon\": \"Trophy\", \"label\": \"Years of Excellence\", \"value\": \"35+\"}, {\"icon\": \"Globe\", \"label\": \"Global Partners\", \"value\": \"100+\"}, {\"icon\": \"Zap\", \"label\": \"Precision Components\", \"value\": \"5000+\"}], \"tagline\": \"At Besmak Components Pvt. Ltd., partnerships are at the core of our growth and innovation.\", \"description\": \"Over the years, we have built strong, long-term relationships with leading automotive OEMs, Tier-1 suppliers, and industry partners, enabling us to deliver high-quality, precision-engineered solutions across the automotive ecosystem.\"}', 2, 1, '2026-03-18 07:10:08', '2026-03-18 07:10:08'),
('ps-hero-section', 'precision-stamping', 'ps-hero', '{\"title\": \"Precision Stamping Manufacturing\", \"series\": [\"025\", \"040\", \"060\", \"070\", \"090\", \"110\", \"250\"], \"description\": \"Delivering high-quality, highly accurate stamped components tailored to the exacting needs of diverse industries. End-to-end solutions that ensure consistency and superior performance.\", \"backgroundImage\": \"\", \"backgroundVideo\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak%20Precision%20Stamping.mp4\"}', 0, 1, '2026-03-13 07:01:21', '2026-03-18 11:47:15'),
('ps-infrastructure-section', 'precision-stamping', 'ps-infrastructure', '{\"title\": \"Cutting-Edge Stamping Machinery\", \"machines\": [{\"brand\": \"BRUDERER (50T & 25T)\", \"specs\": \"Up to 1200 SPM\", \"description\": \"Ideal for intricate and high-volume production with peak BDC accuracy.\"}, {\"brand\": \"SEYI-45T\", \"specs\": \"High Reliability\", \"description\": \"Engineered for consistency in precision metal stamping applications.\"}, {\"brand\": \"ISIS-25T\", \"specs\": \"Micro-Precision\", \"description\": \"Perfect for smaller, high-accuracy components requiring tight tolerances.\"}, {\"brand\": \"NIDEC Knuckle Link\", \"specs\": \"Advanced Motion\", \"description\": \"Equipped with QDC Technology for optimized stroke movement through BDC.\"}], \"description\": \"Operating ten high-speed stamping machines with unique specifications to accommodate diverse manufacturing requirements.\", \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/cutting-edge-machinery.jpg\"}', 2, 1, '2026-03-13 07:01:21', '2026-03-16 10:39:13'),
('ps-materials-section', 'precision-stamping', 'ps-materials', '{\"title\": \"Premium Raw Materials\", \"materials\": [{\"type\": \"Brass\", \"alloys\": \"C2600, C2640, C2700, C2720\", \"properties\": \"Excellent corrosion resistance and machinability.\"}, {\"type\": \"Copper Alloys\", \"alloys\": \"C1100, CuNiSnP, CuNiSi, CuNi3SiMg\", \"properties\": \"Superior electrical and thermal conductivity.\"}, {\"type\": \"Phosphor Bronze\", \"alloys\": \"C5191, C5210\", \"properties\": \"Outstanding strength, wear resistance, and fatigue endurance.\"}, {\"type\": \"Aluminium & Steel\", \"alloys\": \"Industrial Grades\", \"properties\": \"Structural integrity and versatility for multiple applications.\"}], \"description\": \"Prioritizing high-quality materials to guarantee products meet industry standards for durability and electrical performance.\"}', 4, 1, '2026-03-13 07:01:21', '2026-03-13 07:01:21'),
('ps-process-section', 'precision-stamping', 'ps-process', '{\"title\": \"Integrated Manufacturing Capabilities\", \"processes\": [{\"icon\": \"Hammer\", \"title\": \"In-House Tooling\", \"description\": \"Design and manufacture of high-precision tools (5 to 45 station progressive tools).\"}, {\"icon\": \"Zap\", \"title\": \"In-House Welding\", \"description\": \"Brazing and spot welding ensuring durable, high-quality joints.\"}, {\"icon\": \"Droplets\", \"title\": \"In-House Tinning\", \"description\": \"Specialized services to enhance component longevity and performance.\"}, {\"icon\": \"Scissors\", \"title\": \"Precision Tapping\", \"description\": \"Seamless thread formation for superior assembly compatibility.\"}], \"designTitle\": \"Advanced Design & Engineering\", \"designDescription\": \"Leveraging AutoCAD and SolidWorks - Logopress to optimize precision, streamline prototyping, and accelerate timelines.\"}', 3, 1, '2026-03-13 07:01:21', '2026-03-13 07:01:21'),
('ps-segments-section', 'precision-stamping', 'ps-segments', '{\"oems\": [{\"brands\": [\"Hero\", \"Suzuki\", \"Royal Enfield\", \"TVS\", \"Tata\", \"Honda\", \"Hyundai\"], \"category\": \"Automotive\"}, {\"brands\": [\"Salcomp\", \"SFO\", \"Salzer\", \"Harting\"], \"category\": \"Industrial\"}], \"title\": \"Market Segments & OEM Partnerships\", \"segments\": [{\"icon\": \"Car\", \"items\": [\"High-performance terminals\", \"Precision stamping parts\", \"Bus bars for EV BCM\"], \"title\": \"Automotive\"}, {\"icon\": \"Zap\", \"items\": [\"Energy meter terminal blocks\", \"Power measurement parts\", \"Industrial stabilizers\"], \"title\": \"Energy & Industrial\"}, {\"icon\": \"Radio\", \"items\": [\"Signal shields\", \"Conductivity bus bars\", \"EMI protection solutions\"], \"title\": \"Telecom & Electronics\"}], \"oem1Logo1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Hero_MotoCorp-Logo.wine.svg\", \"oem1Logo2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Suzuki_logo_2025_%28vertical%29.svg.png\", \"oem1Logo3\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/TVS-Motor-Logo.jpg\", \"oem1Logo4\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/royal-enfield6316.jpg\", \"oem2Logo1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Hero_MotoCorp-Logo.wine.svg\", \"oem2Logo2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Honda_Logo.svg.png\", \"oem2Logo3\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Hyundai-Logo-2011.png\", \"oem2Logo4\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Tata-Group-logo-3840x2160.png\", \"oemsTitle\": \"Our Strategic Partners\", \"description\": \"Supplying precision components that drive efficiency across vehicle categories and industrial systems.\"}', 5, 1, '2026-03-13 07:01:21', '2026-03-16 12:35:03'),
('ps-stats-section', 'precision-stamping', 'ps-stats', '{\"stats\": [{\"icon\": \"Ruler\", \"label\": \"Material Thickness\", \"value\": \"0.15 - 2.5 MM\", \"subValue\": \"Versatile processing range\"}, {\"icon\": \"Target\", \"label\": \"Tooling Accuracy\", \"value\": \"0.01 MM\", \"subValue\": \"Ultra-precision tolerance\"}, {\"icon\": \"Gauge\", \"label\": \"Part Accuracy\", \"value\": \"0.02 MM\", \"subValue\": \"Consistent quality output\"}, {\"icon\": \"Zap\", \"label\": \"Production Speed\", \"value\": \"1200 SPM\", \"subValue\": \"High-volume efficiency\"}]}', 1, 1, '2026-03-13 07:01:21', '2026-03-13 07:01:21'),
('ps-team-section', 'precision-stamping', 'ps-team', '{\"roles\": [{\"icon\": \"Briefcase\", \"title\": \"Design & Engineering\", \"description\": \"100+ professionals dedicated to high-precision development.\"}, {\"icon\": \"Award\", \"title\": \"Quality Assurance\", \"description\": \"Committed to CMM, VMS, and Profile Projector verified standards.\"}], \"title\": \"Our Team Strength\", \"achievement\": \"Parts accuracy tolerance of 0.02mm – A testament to our skill.\", \"backgroundImage\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/2149271735.jpg\"}', 6, 1, '2026-03-13 07:01:21', '2026-03-16 12:56:16'),
('ps-why-choose-us-section', 'precision-stamping', 'ps-why-choose-us', '{\"usps\": [{\"title\": \"Uncompromised accuracy of 0.01 MM in tooling.\"}, {\"title\": \"High-speed production up to 1200 SPM.\"}, {\"title\": \"Progressive tool solutions up to 45 stations.\"}, {\"title\": \"Advanced QA equipment (CMM, VMS, Projectors).\"}], \"title\": \"Why Choose Besmak Stamping?\", \"summary\": \"By continually upgrading our infrastructure and embracing cutting-edge tech, we remain committed to delivering top-notch stamping solutions.\", \"description\": \"A specialized focus on precision and high-speed efficiency.\"}', 7, 1, '2026-03-13 07:01:21', '2026-03-13 07:01:21'),
('stats-section', 'home-page-id', 'stats-section', '{\"stat1_icon\": \"history\", \"stat2_icon\": \"users\", \"stat3_icon\": \"target\", \"stat4_icon\": \"cog\", \"stat1_label\": \"Legacy & Experience\", \"stat1_value\": \"30+\", \"stat2_label\": \"Workforce Strength\", \"stat2_value\": \"460+\", \"stat3_label\": \"Production Capability\", \"stat3_value\": \"3.2 Million\", \"stat4_label\": \"Technology & Quality\", \"stat4_value\": \"Advanced\"}', 3, 0, '2026-03-02 11:56:51', '2026-03-05 07:15:44'),
('strategic-verticals-section', 'home-page-id', 'strategic-verticals', '{\"heading\": \"Precision Engineered Components\", \"verticals\": [{\"id\": \"connectors\", \"href\": \"/divisions/connectors\", \"image\": \"https://cvnvhpmvk12hdosq.public.blob.vercel-storage.com/div-croped.png\", \"title\": \"Connectors\", \"description\": \"\"}, {\"id\": \"fuse-box\", \"href\": \"/divisions/fuse-box\", \"image\": \"https://cvnvhpmvk12hdosq.public.blob.vercel-storage.com/1f7673b32195506c3e16ca7fedc10f5d3a08d3b0.png\", \"title\": \"Fuse Box\", \"description\": \"\"}, {\"id\": \"dummy-plugs\", \"href\": \"/divisions/dummy-plugs\", \"image\": \"https://cvnvhpmvk12hdosq.public.blob.vercel-storage.com/6bbf541a3751e6d87bb11f101e191a95e5d24d58.png\", \"title\": \"Dummy Plugs\", \"description\": \"\"}, {\"id\": \"relay\", \"href\": \"/divisions/cnh-moulds\", \"image\": \"https://cvnvhpmvk12hdosq.public.blob.vercel-storage.com/6420af06203961d21746289b7e874ff9a58f9440.png\", \"title\": \"Relay\", \"description\": \"\"}], \"subheading\": \"\"}', 5, 1, '2026-03-05 08:36:00', '2026-03-05 16:54:22'),
('supplier-partnerships-1', '7dnzxaec4p2', 'supplier-partnerships', '{\"title\": \"Supplier & Vendor Partnerships\", \"benefits\": [\"High-quality raw materials and components\", \"Advanced coating and finishing technologies\", \"Reliable and efficient supply chain operations\"], \"description\": \"We maintain strong relationships with our supplier network to ensure consistent quality and operational excellence.\"}', 7, 1, '2026-03-18 07:10:17', '2026-03-18 07:10:17'),
('tech-overview', 'home-page-id', 'text-image-section', '{\"title\": \"Modern Manufacturing. Precision Engineering. Proven Legacy.\", \"header\": \"\", \"bgColor\": \"bg-white\", \"imageUrl\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/besmak30_logo.webp\", \"description\": \"For over 30 years, Besmak has supported India\'s industrial growth through innovation, quality and resilience. Rooted in India with a global outlook, we continue to adapt to evolving manufacturing needs while contributing to the spirit of Make in India, backed by strong engineering expertise and trusted industry partnerships.\", \"imagePosition\": \"right\"}', 2, 1, '2026-03-05 06:07:05', '2026-03-11 13:22:30'),
('vg-awards-quality-1', '82yle51rzi2', 'vg-awards-quality', '{\"award1\": \"Preferred Supplier Recognition from leading automotive OEMs and Tier-1 companies\", \"award2\": \"Excellence in Quality & Delivery Performance awards\", \"award3\": \"Recognition for consistent supply chain reliability and on-time delivery\", \"award4\": \"Appreciation awards for customer support and technical collaboration\", \"cert1Name\": \"IATF 16949\", \"cert2Name\": \"ISO 9001\", \"cert3Name\": \"SQ Mark\", \"cert4Name\": \"Industry Standards\", \"cert1Image\": \"https://images.unsplash.com/photo-1576267423048-15c0040fec78?q=80&w=800&auto=format&fit=crop\", \"cert1Label\": \"Automotive Quality Management System\", \"cert2Image\": \"https://images.unsplash.com/photo-1629424707254-8c01a2ba9ab1?q=80&w=800&auto=format&fit=crop\", \"cert2Label\": \"Quality Management Systems\", \"cert3Image\": \"https://images.unsplash.com/photo-1589829085413-56de8ae18c73?q=80&w=800&auto=format&fit=crop\", \"cert3Label\": \"SQ Mark Certification\", \"cert4Image\": \"https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?q=80&w=800&auto=format&fit=crop\", \"cert4Label\": \"Compliance with automotive industry standards and best practices\", \"certsTitle\": \"Certifications\", \"objective1\": \"Continuous improvement in product quality and delivery performance\", \"objective2\": \"Strengthening design, process, and technological capabilities\", \"objective3\": \"Enhancing employee skills through training and development\", \"objective4\": \"Maintaining high standards in safety and operational efficiency\", \"awardImage1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-9.jpg\", \"awardImage2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-4-2.jpg\", \"awardImage3\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-5-1.jpg\", \"awardImage4\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-6-1.jpg\", \"awardImage5\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-7.jpg\", \"awardImage6\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-4-1.jpg\", \"awardImage7\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-3-1.jpg\", \"awardImage8\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/award-2-1.jpg\", \"awardsTitle\": \"Awards & Recognitions\", \"qualityItem1\": \"Focus on \\\"doing it right the first time\\\"\", \"qualityItem2\": \"Continuous improvement in products, processes, and systems\", \"qualityItem3\": \"Enhancing customer satisfaction through quality and reliability\", \"qualityItem4\": \"Adherence to global automotive quality standards\", \"qualityTitle\": \"Quality Policy\", \"awardsTagline\": \"Recognition\", \"qualityTagline\": \"Our Standards\", \"objectivesTitle\": \"Quality Objectives\", \"awardsDescription\": \"Over the years, Besmak has been recognized for its commitment to quality, delivery performance, and customer satisfaction.\", \"qualityCommitment\": \"We are committed to delivering products and services that consistently meet customer expectations and applicable standards.\"}', 4, 1, '2026-03-17 12:52:50', '2026-03-23 08:25:56'),
('vg-commitment-1', '82yle51rzi2', 'vg-commitment', '{\"title\": \"Commitment to Excellence\", \"ctaLink\": \"/contact\", \"ctaText\": \"Contact Us\", \"description\": \"At Besmak, our values and governance practices are not just principles—they are embedded in our everyday operations. They enable us to deliver precision, performance, and trust across every product and partnership.\"}', 6, 1, '2026-03-17 12:52:50', '2026-03-17 12:52:50'),
('vg-core-values-1', '82yle51rzi2', 'vg-core-values', '{\"title\": \"Our Core Values\", \"tagline\": \"Our Foundation\", \"subtitle\": \"The principles that shape every decision, every product, and every partnership.\", \"value1Desc\": \"We conduct our business with the highest standards of honesty and ethical practices. Every decision we make reflects our commitment to fairness, compliance, and long-term trust.\", \"value2Desc\": \"Quality is at the heart of everything we do. From design to delivery, we follow stringent quality systems to ensure our products meet global automotive standards and exceed customer expectations.\", \"value3Desc\": \"We believe in building lasting relationships with our customers by delivering reliable, customized, and value-driven solutions. Our approach is collaborative, responsive, and performance-focused.\", \"value4Desc\": \"We continuously invest in technology, processes, and people to drive innovation. Our focus on improvement enables us to adapt to evolving industry needs, including electric mobility and advanced connectivity.\", \"value5Desc\": \"Our people are our strength. We foster a culture of collaboration, mutual respect, and continuous learning to empower our teams and drive organizational success.\", \"value1Title\": \"Integrity & Ethics\", \"value2Title\": \"Quality Excellence\", \"value3Title\": \"Customer Commitment\", \"value4Title\": \"Innovation & Continuous Improvement\", \"value5Title\": \"Teamwork & Respect\"}', 2, 1, '2026-03-17 12:52:50', '2026-03-17 12:52:50'),
('vg-corporate-governance-1', '82yle51rzi2', 'vg-corporate-governance', '{\"item1\": \"Strong leadership oversight and strategic direction\", \"item2\": \"Transparent decision-making processes\", \"item3\": \"Compliance with industry regulations and standards\", \"item4\": \"Risk management and process control systems\", \"item5\": \"Ethical business conduct across all operations\", \"title\": \"Corporate Governance\", \"bgImage\": \"https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?q=80&w=2070&auto=format&fit=crop\", \"tagline\": \"How We Operate\", \"description\": \"Besmak follows structured governance practices to ensure operational excellence and responsible business conduct:\", \"closingStatement\": \"Our governance framework ensures that we consistently deliver value while maintaining the trust of our customers, partners, and stakeholders.\"}', 3, 1, '2026-03-17 12:52:50', '2026-03-17 12:52:50'),
('vg-ems-safety-1', '82yle51rzi2', 'vg-ems-safety', '{\"emsItem1\": \"Reducing environmental impact through efficient manufacturing processes\", \"emsItem2\": \"Optimizing energy consumption across production and facility operations\", \"emsItem3\": \"Minimizing waste generation and promoting recycling initiatives\", \"emsItem4\": \"Responsible handling and disposal of industrial materials\", \"emsItem5\": \"Compliance with all applicable environmental regulations and standards\", \"emsTitle\": \"Environmental Management System (EMS)\", \"heroTitle\": \"EMS & Safety\", \"heroTagline\": \"Responsibility\", \"safetyItem1\": \"Implementation of strict safety protocols across all production units\", \"safetyItem2\": \"Regular safety training and awareness programs for employees\", \"safetyItem3\": \"Use of appropriate personal protective equipment (PPE)\", \"safetyItem4\": \"Hazard identification and risk assessment processes\", \"safetyItem5\": \"Emergency preparedness and response systems\", \"safetyTitle\": \"Health & Safety at Workplace\", \"heroSubtitle\": \"Committed to Environmental Responsibility and Workplace Safety\", \"emsDescription\": \"We follow structured environmental practices to ensure sustainable manufacturing and responsible resource utilization.\", \"wellbeingItem1\": \"Promoting employee health and well-being\", \"wellbeingItem2\": \"Encouraging participation in safety programs\", \"wellbeingItem3\": \"Building awareness through regular communication and training\", \"wellbeingItem4\": \"Creating a culture where safety is everyone\'s responsibility\", \"wellbeingTitle\": \"Employee Well-being & Engagement\", \"safetyDescription\": \"Safety is a core priority at Besmak. We are committed to providing a safe and healthy work environment for all employees, contractors, and stakeholders.\", \"processSafetyItem1\": \"Standardized operating procedures (SOPs) for all critical processes\", \"processSafetyItem2\": \"Periodic safety audits and inspections\", \"processSafetyItem3\": \"Compliance with industry safety norms and guidelines\", \"processSafetyItem4\": \"Continuous improvement through feedback and incident analysis\", \"processSafetyTitle\": \"Process Safety & Compliance\"}', 5, 1, '2026-03-17 12:52:50', '2026-03-17 12:52:50'),
('vg-hero-1', '82yle51rzi2', 'vg-hero', '{\"title\": \"Our Values & Governance\", \"bgImage\": \"https://images.unsplash.com/photo-1497366216548-37526070297c?q=80&w=2000&auto=format&fit=crop\"}', 1, 1, '2026-03-17 12:52:50', '2026-03-17 12:52:50'),
('video-promo', 'home-page-id', 'video-section', '{\"title\": \"\", \"videos\": [{\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak%20AI%20Video%20-%205.mp4\", \"title\": \"Engineering the Future of  Automotive Connectivity\"}, {\"url\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak-Components-Private-ltd-Banner-67.mp4\", \"title\": \"Building the Backbone of Tomorrow’s Automotive Electronics\"}], \"overlay\": \"false\", \"videoUrl\": \"https://cvnvhpmvk12hdosq.public.blob.vercel-storage.com/Besmak%20Ai%20video.mp4\"}', 1, 1, '2026-03-05 06:06:54', '2026-03-20 12:59:41'),
('vision-and-mission-1', 'about-page', 'overview-section', '{\"title\": \"Precision Engineering for the Global Automotive Industry\", \"image1\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Besmak-Aboutus.jpg\", \"image2\": \"https://fohffyjhcwci6coi.public.blob.vercel-storage.com/Automobile-at-a-glance.jpg\", \"description\": \"Besmak Components is a leading manufacturer of automotive connection systems, precision plastic components, and engineering solutions, serving global OEMs and Tier-1 suppliers. \\nWith advanced manufacturing capabilities, innovation-driven processes, and a highly skilled workforce, Besmak delivers reliable, high-performance components to the automotive industry.\\nFocused on precision, quality, and continuous improvement, the company plays a key role in the automotive wiring harness supply chain, supporting product development, indigenisation, and high-volume manufacturing\", \"visionBadge\": \"Vision\", \"missionBadge\": \"Mission\", \"missionItem1\": \"Besmak to become a World Class Manufacturing Company with a Global presence.\", \"missionItem2\": \"Be a Preferred Company by exceeding Customer Satisfaction.\", \"missionItem3\": \"Maximise Employee Satisfaction by providing a climate for learning and growth.\", \"visionDescription\": \"Globally preferred manufacturer driven by passionate people through innovation\", \"missionDescription\": \"Excellence in Moulding through precision tooling\"}', 1, 1, '2026-03-16 07:54:24', '2026-03-16 11:59:10');
